static const char kWifiConfigPortalSignalingSectionsTemplate[] = "<section class=\"panel\">\n  <div class=\"section-head\"><h2 data-i18n=\"ctcssRoutes\">CTCSS / PL Receive</h2></div>\n  <div class=\"grid\">\n    <form class=\"item-form\" method=\"post\" action=\"/save_signaling\"><label data-i18n=\"decodeMic\">Decode from MIC</label><input type=\"hidden\" name=\"ctcss_rx_mic_present\" value=\"1\"><label class=\"hint\"><input type=\"checkbox\" name=\"ctcss_rx_mic\" value=\"1\" onchange=\"submitSwitch(this)\" {{CTCSS_RX_MIC_CHECKED}}><span data-i18n=\"ctcssDecodeMicText\">Detect the standard CTCSS frequency from microphone/radio audio</span></label></form>\n    <form class=\"item-form\" method=\"post\" action=\"/save_signaling\"><label data-i18n=\"decodeNrl\">Decode from NRL</label><input type=\"hidden\" name=\"ctcss_rx_nrl_present\" value=\"1\"><label class=\"hint\"><input type=\"checkbox\" name=\"ctcss_rx_nrl\" value=\"1\" onchange=\"submitSwitch(this)\" {{CTCSS_RX_NRL_CHECKED}}><span data-i18n=\"ctcssDecodeNrlText\">Detect the standard CTCSS frequency from NRL downlink audio</span></label></form>\n  </div>\n</section>\n<section class=\"panel\">\n  <div class=\"section-head\"><h2 data-i18n=\"mdcRoutes\">MDC1200 Routes</h2><span class=\"hint mono\">{{SIGNALING_STATUS}}</span></div>\n  <div class=\"grid\">\n    <form class=\"item-form\" method=\"post\" action=\"/save_signaling\"><label data-i18n=\"decodeMic\">Decode from MIC</label><input type=\"hidden\" name=\"mdc_rx_mic_present\" value=\"1\"><label class=\"hint\"><input type=\"checkbox\" name=\"mdc_rx_mic\" value=\"1\" onchange=\"submitSwitch(this)\" {{MDC_RX_MIC_CHECKED}}><span data-i18n=\"mdcDecodeMicText\">Decode MDC1200 received from microphone/radio</span></label></form>\n    <form class=\"item-form\" method=\"post\" action=\"/save_signaling\"><label data-i18n=\"decodeNrl\">Decode from NRL</label><input type=\"hidden\" name=\"mdc_rx_nrl_present\" value=\"1\"><label class=\"hint\"><input type=\"checkbox\" name=\"mdc_rx_nrl\" value=\"1\" onchange=\"submitSwitch(this)\" {{MDC_RX_NRL_CHECKED}}><span data-i18n=\"mdcDecodeNrlText\">Decode MDC1200 in network downlink audio</span></label></form>\n    <form class=\"item-form\" method=\"post\" action=\"/save_signaling\"><label data-i18n=\"encodeNrl\">Send to NRL</label><input type=\"hidden\" name=\"mdc_tx_nrl_present\" value=\"1\"><label class=\"hint\"><input type=\"checkbox\" name=\"mdc_tx_nrl\" value=\"1\" onchange=\"submitSwitch(this)\" {{MDC_TX_NRL_CHECKED}}><span data-i18n=\"mdcEncodeNrlText\">Append MDC1200 after local PTT release</span></label></form>\n    <form class=\"item-form\" method=\"post\" action=\"/save_signaling\"><label data-i18n=\"encodeSpeaker\">Send to speaker</label><input type=\"hidden\" name=\"mdc_tx_speaker_present\" value=\"1\"><label class=\"hint\"><input type=\"checkbox\" name=\"mdc_tx_speaker\" value=\"1\" onchange=\"submitSwitch(this)\" {{MDC_TX_SPEAKER_CHECKED}}><span data-i18n=\"mdcEncodeSpeakerText\">Append MDC1200 after NRL voice ends</span></label></form>\n    <form class=\"item-form span-2\" method=\"post\" action=\"/save_signaling\">\n      <div class=\"grid compact-grid\"><div><label data-i18n=\"mdcOpcode\">Opcode (hex)</label><input class=\"mono\" name=\"mdc_opcode\" value=\"{{MDC_OPCODE}}\" maxlength=\"4\"></div><div><label data-i18n=\"mdcArgument\">Argument (hex)</label><input class=\"mono\" name=\"mdc_argument\" value=\"{{MDC_ARGUMENT}}\" maxlength=\"4\"></div><div><label data-i18n=\"mdcUnitId\">MDC ID (4 hex digits)</label><input class=\"mono\" name=\"mdc_unit_id\" value=\"{{MDC_UNIT_ID}}\" maxlength=\"6\"></div></div>\n      <div class=\"actions\"><button class=\"btn-small\" type=\"submit\" data-i18n=\"saveItem\">Save</button></div>\n    </form>\n  </div>\n</section>\n<section class=\"panel\">\n  <div class=\"section-head\"><h2 data-i18n=\"dtmfRoutes\">DTMF Routes</h2></div>\n  <div class=\"grid\">\n    <form class=\"item-form\" method=\"post\" action=\"/save_signaling\"><label data-i18n=\"decodeMic\">Decode from MIC</label><input type=\"hidden\" name=\"dtmf_rx_mic_present\" value=\"1\"><label class=\"hint\"><input type=\"checkbox\" name=\"dtmf_rx_mic\" value=\"1\" onchange=\"submitSwitch(this)\" {{DTMF_RX_MIC_CHECKED}}><span data-i18n=\"dtmfDecodeMicText\">Decode DTMF received from microphone/radio</span></label></form>\n    <form class=\"item-form\" method=\"post\" action=\"/save_signaling\"><label data-i18n=\"decodeNrl\">Decode from NRL</label><input type=\"hidden\" name=\"dtmf_rx_nrl_present\" value=\"1\"><label class=\"hint\"><input type=\"checkbox\" name=\"dtmf_rx_nrl\" value=\"1\" onchange=\"submitSwitch(this)\" {{DTMF_RX_NRL_CHECKED}}><span data-i18n=\"dtmfDecodeNrlText\">Decode DTMF in network downlink audio</span></label></form>\n    <form class=\"item-form\" method=\"post\" action=\"/save_signaling\"><label data-i18n=\"encodeNrl\">Send to NRL</label><input type=\"hidden\" name=\"dtmf_tx_nrl_present\" value=\"1\"><label class=\"hint\"><input type=\"checkbox\" name=\"dtmf_tx_nrl\" value=\"1\" onchange=\"submitSwitch(this)\" {{DTMF_TX_NRL_CHECKED}}><span data-i18n=\"dtmfEncodeNrlText\">Append DTMF after local PTT release</span></label></form>\n    <form class=\"item-form\" method=\"post\" action=\"/save_signaling\"><label data-i18n=\"encodeSpeaker\">Send to speaker</label><input type=\"hidden\" name=\"dtmf_tx_speaker_present\" value=\"1\"><label class=\"hint\"><input type=\"checkbox\" name=\"dtmf_tx_speaker\" value=\"1\" onchange=\"submitSwitch(this)\" {{DTMF_TX_SPEAKER_CHECKED}}><span data-i18n=\"dtmfEncodeSpeakerText\">Append DTMF after NRL voice ends</span></label></form>\n    <form class=\"item-form span-2\" method=\"post\" action=\"/save_signaling\"><label data-i18n=\"dtmfId\">DTMF ID</label><input class=\"mono\" name=\"dtmf_digits\" value=\"{{DTMF_DIGITS}}\" maxlength=\"16\" placeholder=\"123#\"><div class=\"actions\"><button class=\"btn-small\" type=\"submit\" data-i18n=\"saveItem\">Save</button></div></form>\n  </div>\n</section>";
static const char kWifiConfigPortalAprsSectionsTemplate[] = "<section class=\"panel\">\n  <div class=\"section-head\"><h2 data-i18n=\"aprsSwitches\">APRS</h2><span class=\"hint mono\">{{APRS_STATUS}}</span></div>\n  <div class=\"grid\">\n    <form class=\"item-form\" method=\"post\" action=\"/save_aprs\"><label data-i18n=\"aprsEnabled\">APRS</label><input type=\"hidden\" name=\"aprs_present\" value=\"1\"><label class=\"hint\"><input type=\"checkbox\" name=\"aprs_enabled\" value=\"1\" onchange=\"submitSwitch(this)\" {{APRS_ENABLED_CHECKED}}><span data-i18n=\"aprsEnabledText\">Master switch for the APRS transceiver</span></label></form>\n    <form class=\"item-form\" method=\"post\" action=\"/save_aprs\"><label data-i18n=\"aprsNet\">APRS-IS Network</label><input type=\"hidden\" name=\"aprs_net_present\" value=\"1\"><label class=\"hint\"><input type=\"checkbox\" name=\"aprs_net\" value=\"1\" onchange=\"submitSwitch(this)\" {{APRS_NET_CHECKED}}><span data-i18n=\"aprsNetText\">Send beacons to and hear stations from the APRS-IS server</span></label></form>\n    <form class=\"item-form\" method=\"post\" action=\"/save_aprs\"><label data-i18n=\"aprsRfTx\">RF Transmit (AFSK)</label><input type=\"hidden\" name=\"aprs_tx_present\" value=\"1\"><label class=\"hint\"><input type=\"checkbox\" name=\"aprs_tx\" value=\"1\" onchange=\"submitSwitch(this)\" {{APRS_TX_CHECKED}}><span data-i18n=\"aprsRfTxText\">Modulate beacons out through the speaker into the radio</span></label></form>\n    <form class=\"item-form\" method=\"post\" action=\"/save_aprs\"><label data-i18n=\"aprsRfRx\">RF Receive (AFSK)</label><input type=\"hidden\" name=\"aprs_rx_present\" value=\"1\"><label class=\"hint\"><input type=\"checkbox\" name=\"aprs_rx\" value=\"1\" onchange=\"submitSwitch(this)\" {{APRS_RX_CHECKED}}><span data-i18n=\"aprsRfRxText\">Demodulate APRS audio heard on the microphone/radio</span></label></form>\n    <form class=\"item-form\" method=\"post\" action=\"/save_aprs\"><label data-i18n=\"aprsAuto\">Auto interval</label><input type=\"hidden\" name=\"aprs_auto_present\" value=\"1\"><label class=\"hint\"><input type=\"checkbox\" name=\"aprs_auto\" value=\"1\" onchange=\"submitSwitch(this)\" {{APRS_AUTO_CHECKED}}><span data-i18n=\"aprsAutoText\">With a GPS fix, beacon faster while moving (30 s at 60+ km/h, or after a 300 m jump); the interval below is the ceiling when parked</span></label></form>\n    <form class=\"item-form\" method=\"post\" action=\"/save_aprs\"><label data-i18n=\"aprsFixed\">Fixed beacon without GPS</label><input type=\"hidden\" name=\"aprs_fixed_present\" value=\"1\"><label class=\"hint\"><input type=\"checkbox\" name=\"aprs_fixed\" value=\"1\" onchange=\"submitSwitch(this)\" {{APRS_FIXED_CHECKED}}><span data-i18n=\"aprsFixedText\">When GPS has no fix, allow periodic beacons using the configured default position</span></label></form>\n  </div>\n</section>\n<section class=\"panel\" id=\"gps-live-panel\" hidden>\n  <div class=\"section-head\"><h2 data-i18n=\"gpsLive\">GPS Live Information</h2><span class=\"hint mono\" id=\"gps-live-state\"></span></div>\n  <div class=\"grid\">\n    <div><label data-i18n=\"gpsFixStatus\">Fix status</label><div class=\"mono\" id=\"gps-live-fix\">-</div></div>\n    <div><label data-i18n=\"gpsSatellitesUsed\">Satellites used</label><div class=\"mono\" id=\"gps-live-satellites\">-</div></div>\n    <div><label data-i18n=\"gpsSatellitesVisible\">Satellites visible (GSV)</label><div class=\"mono\" id=\"gps-live-visible\">-</div></div>\n    <div><label data-i18n=\"gpsLatitude\">Latitude</label><div class=\"mono\" id=\"gps-live-latitude\">-</div></div>\n    <div><label data-i18n=\"gpsLongitude\">Longitude</label><div class=\"mono\" id=\"gps-live-longitude\">-</div></div>\n    <div><label data-i18n=\"gpsSpeed\">Speed</label><div class=\"mono\" id=\"gps-live-speed\">-</div></div>\n    <div><label data-i18n=\"gpsCourse\">Course</label><div class=\"mono\" id=\"gps-live-course\">-</div></div>\n    <div><label data-i18n=\"gpsAltitude\">Altitude</label><div class=\"mono\" id=\"gps-live-altitude\">-</div></div>\n    <div><label data-i18n=\"gpsAccuracy\">Fix quality / HDOP</label><div class=\"mono\" id=\"gps-live-accuracy\">-</div></div>\n    <div><label data-i18n=\"gpsUpdated\">NMEA updated</label><div class=\"mono\" id=\"gps-live-updated\">-</div></div>\n    <div><label data-i18n=\"gpsGsvUpdated\">GSV updated</label><div class=\"mono\" id=\"gps-live-gsv-updated\">-</div></div>\n    <div class=\"span-2\"><label data-i18n=\"gpsSatelliteSignals\">Satellite signals (constellation/PRN, elevation, azimuth, SNR)</label><div class=\"mono\" id=\"gps-live-signals\" style=\"white-space:pre-wrap;line-height:1.7\">-</div></div>\n  </div>\n</section>\n<section class=\"panel\">\n  <div class=\"section-head\"><h2 data-i18n=\"aprsSettings\">APRS Settings</h2><span class=\"hint\" data-i18n=\"aprsSettingsHint\">Callsign comes from the Radio page; passcode is derived automatically.</span></div>\n  <div class=\"grid\">\n    <form class=\"item-form span-2\" method=\"post\" action=\"/save_aprs\">\n      <div class=\"subgrid\">\n        <div><label data-i18n=\"aprsServer\">APRS-IS Server</label><input name=\"aprs_server\" value=\"{{APRS_SERVER_HOST}}\" placeholder=\"asia.aprs2.net\"></div>\n        <div><label data-i18n=\"aprsPort\">Port</label><input name=\"aprs_port\" value=\"{{APRS_SERVER_PORT}}\"></div>\n        <div><label data-i18n=\"aprsSsid\">SSID (0-15)</label><input name=\"aprs_ssid\" value=\"{{APRS_SSID}}\"></div>\n        <div><label data-i18n=\"aprsSymbol\">Symbol (table+code)</label><input name=\"aprs_symbol\" value=\"{{APRS_SYMBOL}}\" maxlength=\"2\" placeholder=\"/I\"></div>\n        <div><label data-i18n=\"aprsInterval\">Beacon interval (s, 10-3600)</label><input name=\"aprs_interval\" value=\"{{APRS_INTERVAL}}\"></div>\n        <div><label data-i18n=\"aprsPath\">RF path</label><input name=\"aprs_path\" value=\"{{APRS_PATH}}\" placeholder=\"WIDE1-1\"></div>\n        <div><label data-i18n=\"aprsLat\">Default latitude (WGS-84 ddmm.mmmm; N added automatically)</label><input name=\"aprs_lat\" value=\"{{APRS_LAT}}\" placeholder=\"3153.3100\"></div>\n        <div><label data-i18n=\"aprsLon\">Default longitude (WGS-84 dddmm.mmmm; E added automatically)</label><input name=\"aprs_lon\" value=\"{{APRS_LON}}\" placeholder=\"11848.8460\"></div>\n        <div class=\"span-2\"><label data-i18n=\"aprsComment\">Beacon comment (up to 160 UTF-8 bytes)</label><input name=\"aprs_comment\" value=\"{{APRS_COMMENT}}\" maxlength=\"160\" data-max-utf8-bytes=\"160\"></div>\n      </div>\n      <div class=\"actions\"><button class=\"btn-small\" type=\"submit\" data-i18n=\"saveItem\">Save</button><button class=\"btn-small\" type=\"button\" onclick=\"submitFormAction(this, 'aprs_beacon')\" data-i18n=\"aprsBeaconNow\">Beacon now</button></div>\n    </form>\n  </div>\n</section>\n<section class=\"panel\">\n  <div class=\"section-head\"><h2 data-i18n=\"aprsStations\">Stations Heard</h2><span class=\"hint mono\" id=\"aprs-stn-status\"></span></div>\n  <div class=\"grid\">\n    <div class=\"span-2\" style=\"overflow-x:auto\">\n      <table class=\"mono\" id=\"aprs-stn-table\" style=\"width:100%;border-collapse:collapse;font-size:12px\">\n        <thead><tr style=\"text-align:left\">\n          <th data-i18n=\"aprsStnCall\">Callsign</th><th data-i18n=\"aprsStnPos\">Lat / Lon</th><th data-i18n=\"aprsStnAlt\">Alt</th>\n          <th data-i18n=\"aprsStnDist\">Distance</th><th data-i18n=\"aprsStnSpeed\">Speed</th><th data-i18n=\"aprsStnCourse\">Course</th>\n          <th>via</th><th data-i18n=\"aprsStnAge\">Heard</th><th data-i18n=\"aprsStnComment\">Comment</th>\n        </tr></thead>\n        <tbody id=\"aprs-stn-body\"><tr><td colspan=\"9\" class=\"hint\" data-i18n=\"aprsStnEmpty\">No stations heard yet.</td></tr></tbody>\n      </table>\n    </div>\n    <script>\n    (function(){\n      function fmt(v, suffix, digits) {\n        if (v === null || v === undefined || !Number.isFinite(Number(v))) return '-';\n        v = Number(v);\n        return v.toFixed(digits === undefined ? 0 : digits) + (suffix || '');\n      }\n      function text(id, value) {\n        var el = document.getElementById(id);\n        if (el) el.textContent = value;\n      }\n      function tr(key, fallback) {\n        return typeof t === 'function' ? t(key) : fallback;\n      }\n      function renderGps(gps) {\n        var panel = document.getElementById('gps-live-panel');\n        if (!panel) return;\n        var connected = !!(gps && gps.connected);\n        panel.hidden = !connected;\n        if (!connected) return;\n        var fixed = !!gps.fix;\n        text('gps-live-state', 'NMEA: OK');\n        text('gps-live-fix', fixed ? tr('gpsFixed', 'Fixed') : tr('gpsAcquiring', 'Acquiring'));\n        text('gps-live-satellites', gps.satellites === undefined ? '-' : String(gps.satellites));\n        text('gps-live-visible', gps.visible_satellites === undefined ? '-' : String(gps.visible_satellites));\n        text('gps-live-latitude', fixed ? fmt(gps.lat, '', 6) : '-');\n        text('gps-live-longitude', fixed ? fmt(gps.lon, '', 6) : '-');\n        text('gps-live-speed', fixed ? fmt(gps.speed, ' km/h', 1) : '-');\n        text('gps-live-course', fixed ? fmt(gps.course, '\\u00b0', 0) : '-');\n        text('gps-live-altitude', fixed ? fmt(gps.alt, ' m', 1) : '-');\n        var quality = gps.quality === undefined ? '-' : 'Q=' + gps.quality;\n        if (gps.hdop !== undefined) quality += ' / HDOP=' + fmt(gps.hdop, '', 1);\n        text('gps-live-accuracy', quality);\n        text('gps-live-updated', fmt(Number(gps.age_ms) / 1000, ' s', 1));\n        text('gps-live-gsv-updated', gps.gsv_age_ms === undefined ? '-' :\n             fmt(Number(gps.gsv_age_ms) / 1000, ' s', 1));\n        var signals = Array.isArray(gps.satellite_signals) ? gps.satellite_signals.slice() : [];\n        signals.sort(function(a, b) { return Number(b.snr) - Number(a.snr); });\n        text('gps-live-signals', signals.length ? signals.map(function(s) {\n          var id = String(s.talker || '--') + String(s.prn).padStart(2, '0');\n          var elevation = Number(s.elevation) >= 0 ? s.elevation + '\\u00b0' : '--';\n          var azimuth = Number(s.azimuth) >= 0 ? s.azimuth + '\\u00b0' : '--';\n          var snr = Number(s.snr) >= 0 ? s.snr + ' dB-Hz' : '--';\n          return id + '  EL ' + elevation + '  AZ ' + azimuth + '  SNR ' + snr;\n        }).join('\\n') : tr('gpsNoSatelliteSignals', 'No GSV satellite signal data'));\n      }\n      function refresh() {\n        fetch('/aprs/stations').then(function(r){ return r.json(); }).then(function(data){\n          if (!data) return;\n          renderGps(data.gps_info);\n          var body = document.getElementById('aprs-stn-body');\n          if (!body || !Array.isArray(data.stations)) return;\n          var st = document.getElementById('aprs-stn-status');\n          if (st) st.textContent = (data.net ? 'APRS-IS: OK' : 'APRS-IS: --') +\n                                   '  GPS: ' + (data.gps ? 'FIX' :\n                                      (data.gps_info && data.gps_info.connected ? 'DATA' : '--')) +\n                                   '  RX: ' + data.rx + '  TX: ' + data.tx;\n          body.innerHTML = '';\n          if (!data.stations.length) {\n            var tr = document.createElement('tr');\n            var td = document.createElement('td');\n            td.colSpan = 9; td.className = 'hint';\n            td.textContent = 'No stations heard yet.';\n            tr.appendChild(td); body.appendChild(tr);\n            return;\n          }\n          data.stations.forEach(function(s){\n            var tr = document.createElement('tr');\n            function cell(text) { var td = document.createElement('td'); td.textContent = text; tr.appendChild(td); }\n            cell(s.name);\n            cell(fmt(s.lat, '', 4) + ', ' + fmt(s.lon, '', 4));\n            cell(fmt(s.alt, ' m'));\n            cell(fmt(s.dist, ' km', 1));\n            var spd = (s.spd !== null && s.spd !== undefined) ? fmt(s.spd, ' km/h')\n                    : ((s.dspd !== null && s.dspd !== undefined) ? '~' + fmt(s.dspd, ' km/h') : '-');\n            cell(spd);\n            cell(s.crs ? (s.crs % 360) + '\u00b0' : '-');\n            cell(s.rf ? 'RF' : 'IS');\n            cell(s.age < 60 ? s.age + 's' : Math.floor(s.age / 60) + 'm');\n            cell(s.cmt || '');\n            body.appendChild(tr);\n          });\n        }).catch(function(){});\n      }\n      refresh();\n      setInterval(refresh, 1000);\n    })();\n    </script>\n  </div>\n</section>";

#endif
